const int MAX_LEN  = 150; // second dim of used array
int Dp[150 * 150]; // used as Dp[150][150]
const int MAX_DP = 150;

int dis_abs(int a,int b) {
    if (a > b)
        return a - b;
    return b - a;
}

int cal(int i,int j) {
    return MAX_LEN * i + j;
}

int min(int a,int b) {
    if (a > b)
        return b;
    return a;
}

int _strlen(char str[]) {
    int i;
    for (i = 0;str[i] != 0;i = i + 1) ;
    return i;
}


int editdistDP(char str1[], char str2[]) 
{   
    int i,j,a,b,c,min1;
    int len1 = _strlen(str1) + 1;
    int len2 = _strlen(str2) + 1;

    for (j = 0;j <= len2;j = j + 1) {
        Dp[cal(0,j)] = j;
    }

    for (i=1; i<=len1; i = i + 1) {
        Dp[cal(i,0)] = i;
        int min_dis = MAX_DP;
        for (j=1; j<=len2; j = j + 1) {
            if (str1[i-1] != str2[j-1]) {
                a = Dp[cal(i,j-1)];
                b = Dp[cal(i-1,j)];
                c = Dp[cal(i-1,j-1)];
                min1 = min(a,b);
                Dp[cal(i,j)] = 1 + min(min1,c);
            } else {
                Dp[cal(i,j)] = Dp[cal(i-1,j-1)];
            }
        }
    }
    return Dp[cal(len1,len2)];
}

void _strcat(char str1[],char str2[]) {
    int i,len1 = _strlen(str1),len2 = _strlen(str2);
    for (i = 0;i < len2 + 1;i = i + 1) {
        str1[i + len1] = str2[i];
    }
}

