// Read a string ending in '\f' ('\f' not included) ; 
void read(char s[])  {
    int i;
    char ch;
    for(i = 0;;i = i + 1) {
        ch = getchar();
        if (ch == '\f') {
            s[i] = '\0';
            return;
        }
        s[i] = ch;
    }
}

